135→              }
136→            ];
137→          }
138→        ];
139→        PermissionRequest = [
140→          {
141→            hooks = [
142→              {
143→                type = "command";
144→                command = "${claudeDotfilesDir}/hooks/notify.zsh";
145→              }
146→            ];
147→          }
148→        ];
149→        Notification = lib.optionals pkgs.stdenv.isDarwin [
150→          {
151→            hooks = [
152→              {
153→                type = "command";
154→                command = "CMUX_BIN=\"\"; if command -v cmux >/dev/null 2>&1; then CMUX_BIN=cmux; elif [ -x /Applications/cmux.app/Contents/Resources/bin/cmux ]; then CMUX_BIN=/Applications/cmux.app/Contents/Resources/bin/cmux; fi; if [ -n \"$CMUX_TAB_ID\" ] && [ -n \"$CMUX_BIN\" ]; then \"$CMUX_BIN\" set-app-focus active; \"$CMUX_BIN\" select-workspace --workspace \"$CMUX_TAB_ID\" && ${jq} -r '.message' | xargs -I {} \"$CMUX_BIN\" notify --title \"Claude Code\" --body \"{}\" --tab \"$CMUX_TAB_ID\"; else ${jq} -r '.message' | xargs -I {} ${terminal-notifier} -message \"{}\" -title \"Claude Code\" -group \"$(pwd):hook\"; fi";
155→              }
156→            ];
157→          }
158→        ];
159→        WorktreeCreate = [
160→          {
161→            hooks = [
162→              {
163→                type = "command";
164→                command = "${claudeDotfilesDir}/hooks/worktree.zsh";
165→              }
166→            ];
167→          }
168→        ];
169→        WorktreeRemove = [
170→          {
171→            hooks = [
172→              {
173→                type = "command";
174→                command = "${claudeDotfilesDir}/hooks/worktree.zsh";
175→              }
176→            ];
177→          }
178→        ];
179→      };
180→    };
181→    "claude/hooks".source = config.lib.file.mkOutOfStoreSymlink "${claudeDotfilesDir}/hooks";
182→    "claude/CLAUDE.md".source = config.lib.file.mkOutOfStoreSymlink "${claudeDotfilesDir}/CLAUDE.md";
183→    "claude/commands".source = config.lib.file.mkOutOfStoreSymlink "${claudeDotfilesDir}/commands";
184→    "claude/agents".source = config.lib.file.mkOutOfStoreSymlink "${claudeDotfilesDir}/agents";
185→    "claude/output-styles".source =
186→      config.lib.file.mkOutOfStoreSymlink "${claudeDotfilesDir}/output-styles";
187→    "claude/rules".source = config.lib.file.mkOutOfStoreSymlink "${claudeDotfilesDir}/rules";
188→  };
189→
190→  home.activation.setupRtk = lib.hm.dag.entryAfter [ "writeBoundary" ] ''
191→    echo "Setting up rtk hook..."
192→    ${rtk} init -g --hook-only --no-patch 2>/dev/null || true
193→  '';
194→
195→  home.activation.validateClaudeSettings = lib.hm.dag.entryAfter [ "writeBoundary" ] ''
196→    SETTINGS_FILE="${claudeConfigDir}/settings.json"
197→    SCHEMA_URL=$(${jq} -r '.["$schema"]' "$SETTINGS_FILE")
198→
199→    echo "Validating Claude Code settings.json..."
200→    if ${pkgs.check-jsonschema}/bin/check-jsonschema --schemafile "$SCHEMA_URL" "$SETTINGS_FILE" 2>&1; then
201→      echo "Claude Code settings.json validation passed"
202→    else
203→      echo "Claude Code settings.json validation warning: schema validation failed (schemastore may be outdated)" >&2
204→    fi
205→  '';
206→}
